var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"나나하라 가문 연합 관할 \\n<color=#ffd34c>제7 봉인역</color>","JPN":"七原家連合管轄 \\n<color=#ffd34c>第七封印域</color>","ENG":"Nanahara Family Alliance Territory \\n<color=#ffd34c>The 7th Seal Domain</color>","TWN":"七原家族聯盟管轄 \\n<color=#ffd34c>第7封印域</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"분명 이쯤 어디에 있었을 텐데.","JPN":"確かこの辺りだったと思うんだけど。","ENG":"It must be here somewhere...","TWN":"肯定就在這附近。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토! 이쪽이다!","JPN":"湊！　こっちだ！","ENG":"Minato, over here!","TWN":"南裕夏！這邊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이게 대체…… 어떻게 된 거지?","JPN":"これはいったい……どういうこと？","ENG":"What... What happened?","TWN":"這……到底是怎麼回事？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"누가 집에 불을 질렀어.","JPN":"誰かが小屋に火をつけたようだな。","ENG":"Someone set fire to the cabin.","TWN":"有人放火要燒掉這裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"주변 나무들이 아직 멀쩡한 걸 봐선 단순한 사고가 아니야.","JPN":"周辺の木は燃えてないし、単純な事故じゃないな。","ENG":"The trees are not burnt. I don’t think this was an accident.","TWN":"周圍的樹木都沒有被火燒的痕跡，這應該不是單純的意外。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"야, 미나토! 뭘 어쩌려는 거야!","JPN":"おい、湊！　何やってんだよ！","ENG":"Hey, Minato! What are you doing?","TWN":"喂，南裕夏！你想在幹嘛？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불을 끄기엔 늦었어! 전부 타버리기 전에 뭐라도 건져야지!","JPN":"火を消すには遅すぎる！\\n全部燃えてしまう前に何でもいいから見つけないと！","ENG":"It’s too late to put out the fire! I have to find something before it’s all gone!","TWN":"來不及滅火了！在全部燒光前，能救什麼算什麼吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"크윽……","JPN":"くう……","ENG":"Gah...","TWN":"呃呃……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불길이 너무 심해서 앞이 잘 안 보여.","JPN":"炎が強すぎて前がよく見えない……","ENG":"The fire is too big; I can’t see anything.","TWN":"因為火勢太大，看不清處前面。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……응? 저건?","JPN":"……うん？　あれは？","ENG":"Huh? What’s that?","TWN":"……嗯？那是？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너 대체 뭐하고 있는 거야!","JPN":"お前、何考えてんだ！","ENG":"What the heck are you doing?","TWN":"你到底在做什麼！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우왓!","JPN":"うわっ！","ENG":"Wah!","TWN":"噢唔！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"콜록, 콜록……. 하아…….","JPN":"ゴホッゴホッ……はあ……","ENG":"*Cough*, *Cough*","TWN":"咳咳，咳咳……呼呼……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"야, 미나토! 너 무슨 짓이야! 무너지기 직전이었다고!","JPN":"おい、湊！　お前正気か？　崩れる寸前だったぞ！？","ENG":"Hey, Minato! What were you thinking? The cabin was about to collapse!","TWN":"喂，南裕夏！你在幹什麼！屋子就快塌了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"콜록……","JPN":"ゲホッ……","ENG":"*Cough*","TWN":"咳咳……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키.","JPN":"雅紀。","ENG":"Masaki.","TWN":"雅紀。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐! 왜! 뭐!","JPN":"な、なんだよ！","ENG":"What! What?","TWN":"幹嘛！什麼？幹嘛啦！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이거…… 뭔지 알아보겠어?","JPN":"これ……何かわかる？","ENG":"Do you recognize this?","TWN":"你知道……這是什麼嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…뭐?","JPN":"……なんだ？","ENG":"What?","TWN":"…什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"가면이잖아? 여우인가? 저 안에서 이걸 찾았다고?","JPN":"お面だろ？　狐か？　あの中で見つけたのか？","ENG":"It’s a mask. A fox mask. You found this in the cabin?","TWN":"這不是面具嗎？是狐狸嗎？這是你在裡面找到的嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그냥 장식일 수도 있잖아. 무슨 근거로 그런 걸 가져온 거야?","JPN":"ただの飾りかもしれないだろ？\\nなんでそんなものを拾って来たんだ？","ENG":"But it could be just a decoration. Why did you bring it?","TWN":"說不定只是裝飾而已，你搶救它出來的時候在想什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불에 탄 바닥 아래에 있었어.","JPN":"燃え焦げた床下にあったんだ。","ENG":"It was right under the scorched floor.","TWN":"這個面具藏在地板底下。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"단순한 장식용이라면 그런 식으로 숨겨져 있진 않았겠지.","JPN":"ただの飾りなら床下には隠さないだろ。","ENG":"I don’t think she would have hidden it if it was just an ordinary decoration.","TWN":"如果只是單純的裝飾品，應該不用藏起來吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"게다가… 꼭 단서가 아니라도 상관없어.","JPN":"それに……手がかりじゃなくたっていい。","ENG":"Plus... even if it’s not a clue...","TWN":"而且…就算不是線索也沒關係。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하야미 씨에게 소중한 물건일 수도 있는 거잖아.","JPN":"速水さんの大切なものかもしれないから。","ENG":"It could be important to Hayami.","TWN":"這個東西對速水早苗來說或許很重要。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하아, 너 말이야……","JPN":"はあ、お前さぁ……","ENG":"Geez, you...","TWN":"哀～我說你……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"의도가 좋은 건 둘째 치고, 너무 무모하잖아.","JPN":"やってることは立派だが、無謀すぎるぞ。","ENG":"I know you mean good, but stop being so reckless, man.","TWN":"你的出發點是好的，但是太衝動了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나서지 않으면 단명할 걱정이라도 없지.","JPN":"余計なことに首を突っ込んでも、いいことなんか何もないぜ。","ENG":"Otherwise you’ll kill yourself.","TWN":"你這樣很難長命百歲吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하… 일단은 믿는 구석이 있는 카운터잖아?","JPN":"ハハ……まあ、一応カウンターだしさ。","ENG":"Hah hah, I am a Counter. I’ll be okay.","TWN":"哈哈…誰叫我是值得信任的制裁者呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…못 말리겠네.","JPN":"…まったく、お手上げだ。","ENG":"*Sigh* You’re unbelievable.","TWN":"…真拿你沒辦法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"미나토… 님?","JPN":"湊……様？","ENG":"Mr…. Nayuka?","TWN":"南裕夏…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……치나츠? 네가 왜 여기에……","JPN":"……千夏？　どうして君がここに……？","ENG":"Chinatsu? What are you doing here?","TWN":"……千夏？你怎麼會在這裡……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"여기 계시면 안 됩니다! 어서……!","JPN":"ここにいてはいけません！　早く……！","ENG":"You’re not supposed to be here. You should—","TWN":"你不能在這裡！快…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_SILHOUETTE","text":{"KOREA":"어머나, 두 분.","JPN":"あら、お二人とも。","ENG":"Oh, hello, you two.","TWN":"唷！是二位。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_SILHOUETTE","text":{"KOREA":"여기서 뵙다니 우연이군요.","JPN":"ここでお会いするなんて奇遇ですね。","ENG":"What an unexpected surprise.","TWN":"這麼巧在這裡遇到。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"아니면…… 두 분의 운이 나빴다고 해야 할까요?","JPN":"それとも……お二人の運が悪かったのでしょうか？","ENG":"Or rather... an unfortunate surprise for you.","TWN":"還是…該說是二位的運氣不好呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"장로님? 무슨 말을 하는 거야?","JPN":"長老？　何を言っている？","ENG":"Elder? What are you talking about?","TWN":"長老？你這什麼意思？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하야미 사나에의 범행 증거를 찾을 유일한 장소를 불태운 것도 모자라……","JPN":"速水早苗の犯行の証拠を探せる唯一の場所を燃やした挙句……","ENG":"You just burnt the only place where clues for Hayami Sanae’s crime might be found...","TWN":"不只燒掉唯一能找到速水早苗犯罪證據的地方…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저희에게 증거 인멸의 현장을 들켜버리다니 말이지요.","JPN":"私たちに証拠隠滅の現場を取り押さえられるとは。","ENG":"And you were caught at the scene of crime.","TWN":"還被抓到你們正在湮滅證據。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"무, 무슨 소리야? 이건 오해라고! 이 집은 우리가 왔을 때부터 이미 불타고 있었어!","JPN":"どういうことだ？　誤解だ！　オレたちが着いた時にはすでに燃えていたぞ！","ENG":"W-what? This is a misunderstanding. The cabin was already on fire when we got here!","TWN":"你…胡說什麼！這是誤會！我們到的時候屋子就已經著火了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"구차한 변명이로군.","JPN":"苦しい言い訳だな。","ENG":"A lame excuse.","TWN":"不需要再做無謂的解釋。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"방금 전까지만 해도 당주님을 암살하려던 현장에 있던 용의자들이 이곳에 나타나서 한다는 말이 고작 오해라고?","JPN":"当主が暗殺されかけた現場にいた二人が\\n揃ってここに現れたというのに、それを誤解だと？","ENG":"You were at the scene where assassins attacked the Alliance leader, and now you’re here. Do you expect us to believe you?","TWN":"剛剛明明還在暗殺堂主的現場，現在就出現在這裡，用誤會兩個字就說得過去嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"하필 덜미를 잡힌 두 사람이 연합의 부적응자와 방계 출신이란 것도 <color=#ffd34c>우연</color>이라고 잡아뗄 텐가?","JPN":"よりによって二人が連合の不適合者と傍系出身だということも\\n<color=#ffd34c>偶然</color>と言い放つのか？","ENG":"One is a misfit and the other is from the collateral family. Are you going to say all of this is just a <color=#ffd34c>coincidence</color>?","TWN":"就這麼巧，被逮個正著的兩人，一個是不適應聯盟，一個是出身自旁系，這也要硬說是<color=#ffd34c>湊巧</color>嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇! 억지부리면서 생사람 잡지 말라고!","JPN":"チッ！　だから違うっていってんだろ！","ENG":"Bah! Stop being ridiculous!","TWN":"嗟！你少在那邊含血噴人！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"카토리 마사키 당주.","JPN":"香取雅紀当主。","ENG":"Sir Katori Masaki.","TWN":"香取雅紀堂主。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"자네도 의결 때 나나하라 당주를 바꾸자는 쪽에 찬성했었지.","JPN":"お前は議決の際に当主交代に賛成していたな。","ENG":"You voted for dismissing the current Nanahara leader.","TWN":"你在表決時同意換掉七原堂主吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"허허, 속으론 당주를 원망하고 있던 것 아니었나?","JPN":"内心はご当主を恨んでいたのではないかね？","ENG":"You had resentment against her, didn’t you?","TWN":"呵呵，這就代表你心裡也很不滿意堂主不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"자네 아버지가 그런 꼴을 당한 것도 당주의 잘못된 결정 때문에…….","JPN":"父上があんな目にあったのは、ご当主の誤った決断のせいで……","ENG":"For what happened to your father...","TWN":"你父親會落得那般下場，也是因為堂主錯誤的決定…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"시끄러워, 영감탱이!","JPN":"うるせえ、このクソジジイ！","ENG":"Shut up, old man!","TWN":"你給我閉嘴，臭老頭！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……큭?!","JPN":"……くっ！？","ENG":"Urgh?!","TWN":"……唔？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그만두시지요, 마사키 공.","JPN":"そこまでです、雅紀様。","ENG":"You shall stop, Sir Masaki.","TWN":"到此為止吧，雅紀。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이 자리에서 난폭하게 굴어봐야, 그대의 입지만 나빠질 뿐입니다.","JPN":"ここで暴れたところで立場が悪くなるだけです。","ENG":"Attacking someone won’t help you.","TWN":"在這裡動手只會使你更難堪。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 무슨 힘이 이렇게 세?","JPN":"な、何だ？　なんでこんなに力が強いんだ？","ENG":"W-what was that? How could you be so strong?","TWN":"什…什麼鬼？力氣也未免太大？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"흥, 이런 짓을 저지를 거라면 애초에 들키지 말았어야지.","JPN":"何かを企むのであれば、もう少しうまくやるべきじゃったな。","ENG":"You shouldn't have been caught in the first place if you were going to do something like this.","TWN":"哼，敢做這種事，就要有本事不被發現嘛。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 노망난 영감탱이! 웃기지 말라고 해! 나한테 그 문제랑 이건 전혀 관계가 없다고!","JPN":"このクソジジイ！　笑わせんな！　それとこれとは何の関係もない！","ENG":"You crazy old man! Are you kidding me? I had nothing to do with this!","TWN":"你這個臭老頭！少笑掉人大牙！不要汙衊我，我和件事沒關係！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"크아악! 뭐하는 짓이야! 왜 우릴 여기에 가두는 건데!","JPN":"くそっ！　何すんだよ！　なんでオレたちをここに閉じ込めるんだ！","ENG":"Argh! What are you doing? Why are you locking us up?","TWN":"喂喂喂！幹什麼！爲什麼把我們關在這裡！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"변호사 불러! 증거를 가져오라고!","JPN":"弁護士を呼べ！　証拠を持って来い！","ENG":"I want a lawyer! Bring me the evidence!","TWN":"叫律師來！有證據嗎！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"제대로 된 조사를 진행하기 위한 절차이니, 이해해주시지요.","JPN":"調査のための措置ですので、ご理解ください。","ENG":"This is a just a process. Please stay calm.","TWN":"這是進行調查的正常程序，還請見諒。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"두 분은 하야미 사나에의 범행 사실이 입증될 때까지 이곳에서 기다리시면 됩니다.","JPN":"お二人には速水早苗の犯行が立証されるまで、\\nここでお待ちいただきます。","ENG":"You two will have to wait here until Hayami Sanae’s crime is proven.","TWN":"二位就待在這裡，直到速水早苗的犯罪事實查證爲止。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"물론 그땐 자네들이 증거를 인멸한 공범이 아니라는 것도 함께 입증해야겠지만 말이지.","JPN":"もちろん、お前たちが証拠を隠滅した共犯でないことも立証する必要があるがな。","ENG":"Of course, you’ll also have to prove yourselves that you’re not her accomplices.","TWN":"當然，到時候你們也必須證明，你們不是湮滅證據的共犯。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};